API_name: rule_search_by_query
Description:
{
  "description": "使用語意向量搜尋查詢教務處法規章則（學則、辦法、要點等）。",
  "required_parameters": [
    {
      "name": "query",
      "type": "STRING",
      "description": "查詢問題或關鍵字，例如「轉系辦法」、「請假流程」"
    }
  ],
  "optional_parameters": [
    {
      "name": "top_k",
      "type": "NUMBER",
      "description": "回傳最相關的結果數量（1-10）",
      "default": 5
    }
  ]
}

